import React from 'react';
import {
  LinErpListFilterBar,
  SearchInput,
  type AccountSearchRecord,
  type SearchInputConfig,
} from '@linm-soft-org/linm-web-common-components';
import { formatAccountDisplay } from '../../../components/search/accountSearchApi';
import erp from '../../../styles/erpPage.module.css';
import styles from './SoCaiReportFilterBar.module.css';

export type SoCaiReportFilterBarLabels = {
  fieldAccount: string;
  fieldDateRange: string;
  expandDateRangeAriaLabel: string;
  view: string;
  accountPlaceholder: string;
};

export type SoCaiReportFilterBarProps = {
  testIdPrefix: string;
  labels: SoCaiReportFilterBarLabels;
  accountSearchConfig: SearchInputConfig<AccountSearchRecord>;
  accountCode: string;
  accountName: string;
  accountError?: string;
  onAccountChange: (code: string, name: string) => void;
  onAccountClear: () => void;
  fromDate?: string;
  toDate?: string;
  onDateChange: (fromDate?: string, toDate?: string) => void;
  onView: () => void;
  loading?: boolean;
};

export const SoCaiReportFilterBar: React.FC<SoCaiReportFilterBarProps> = ({
  testIdPrefix,
  labels,
  accountSearchConfig,
  accountCode,
  accountName,
  accountError,
  onAccountChange,
  onAccountClear,
  fromDate,
  toDate,
  onDateChange,
  onView,
  loading = false,
}) => (
  <LinErpListFilterBar
    testIdPrefix={testIdPrefix}
    fromDate={fromDate}
    toDate={toDate}
    onDateChange={onDateChange}
    dateLabel={labels.fieldDateRange}
    expandDateRangeAriaLabel={labels.expandDateRangeAriaLabel}
    onSearch={onView}
    searchAriaLabel={labels.view}
    loading={loading}
    leading={(
      <div
        className={styles.filterFieldAccount}
        data-testid={`${testIdPrefix}-field-account`}
      >
        <div className={`${styles.filterFieldAccountInner} ${erp.searchInGrid}`}>
          <SearchInput
            config={accountSearchConfig}
            label={labels.fieldAccount}
            required
            error={accountError}
            value={accountCode}
            primaryDisplay={formatAccountDisplay(accountCode, accountName)}
            onChange={a => onAccountChange(a.code, a.name)}
            onClear={onAccountClear}
            showSecondaryInput={false}
            placeholder={labels.accountPlaceholder}
          />
        </div>
      </div>
    )}
  />
);

export default SoCaiReportFilterBar;
